#include "SYsULexer.h"
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <sstream>
#include <vector>

// clang 格式的 token 类型名映射
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Return", "return" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "Plus", "plus" },
  { "Comma", "comma" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Less", "less" },
  { "Greater", "greater" },
  { "LessEqual", "lessequal" },
  { "GreaterEqual", "greaterequal" },
  { "EqualEqual", "equalequal" },
  { "ExclaimEqual", "exclaimequal" },
  { "Exclaim", "exclaim" },
  { "PipePipe", "pipepipe" },
  { "AmpAmp", "ampamp" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Const", "const" },
  { "Void", "void" },
};

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const std::string& filename,
            int line,
            int col,
            bool startOfLine,
            bool leadingSpace)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>";

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  std::ostringstream locInfo;
  locInfo << " Loc=<" << filename << ":" << line << ":" << col << ">";

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " ''";

  outFile << "\t";
  if (startOfLine)
    outFile << " [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << "\t" << locInfo.str() << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  auto allTokens = tokens.getTokens();

  // 遍历 source 字符串，构建每个字符对应的行号、列号、文件名的映射
  std::string source = input.toString();
  std::vector<int> charLine(source.size() + 1, 1);
  std::vector<int> charCol(source.size() + 1, 1);
  std::vector<std::string> charFile(source.size() + 1, "0");

  int curLine = 1;
  int curCol = 1;
  std::string curFile = "0";

  size_t i = 0;
  while (i < source.size()) {
    charFile[i] = curFile;
    charLine[i] = curLine;
    charCol[i] = curCol;

    // 检查是否是 # marker 行
    if (source[i] == '#' && (i == 0 || source[i - 1] == '\n' || source[i - 1] == '\r')) {
      // 读取整行
      size_t end = source.find('\n', i);
      if (end == std::string::npos) end = source.size();
      std::string line = source.substr(i, end - i);
      std::istringstream iss(line.substr(1));
      int nl = 0;
      std::string fn;
      iss >> nl >> fn;
      if (!fn.empty() && fn[0] == '"') {
        fn = fn.substr(1, fn.length() - 2);
      }
      if (!fn.empty()) curFile = fn;
      if (nl > 0) {
        curLine = nl - 1; // 下一行行号是 nl
      }
      // 跳过该行
      i = end + 1;
      curCol = 1;
      if (nl > 0) {
        curLine = nl;
      }
      continue;
    }

    if (source[i] == '\r') {
      if (i + 1 < source.size() && source[i + 1] == '\n') {
        i++;
      }
      curLine++;
      curCol = 1;
      i++;
      continue;
    }
    if (source[i] == '\n') {
      curLine++;
      curCol = 1;
      i++;
      continue;
    }

    curCol++;
    i++;
  }
  // 末尾位置
  charFile[source.size()] = curFile;
  charLine[source.size()] = curLine;
  charCol[source.size()] = curCol;

  // 现在遍历 allTokens 输出
  for (auto&& token : allTokens) {
    if (token->getChannel() == SYsULexer::HIDDEN)
      continue;

    size_t startIdx = token->getStartIndex();
    int line = charLine[startIdx];
    int col = charCol[startIdx];
    std::string filename = charFile[startIdx];

    bool startOfLine = false;
    bool leadingSpace = false;

    if (startIdx == 0) {
      startOfLine = true;
    } else {
      char prev = source[startIdx - 1];
      if (prev == '\n' || prev == '\r') {
        startOfLine = true;
      } else if (prev == ' ' || prev == '\t') {
        leadingSpace = true;
      }
    }

    // 对于 EOF token
    if (token->getType() == antlr4::Token::EOF) {
      // eof 行号列号为最后一个 token 行号，列号 + 1
      size_t lastIdx = source.size();
      line = charLine[lastIdx];
      col = charCol[lastIdx];
      filename = charFile[lastIdx];
      startOfLine = false;
      leadingSpace = false;
    }

    print_token(token, tokens, outFile, lexer, filename, line, col,
                startOfLine, leadingSpace);
  }
}

