      }
      if (!fn.empty()) curFile = fn;
      if (nl > 0) {
        curLine = nl - 1; // 下一行行号是 nl
      }
      // 跳过该行
      i = end + 1;
      curCol = 1;
      if (nl > 0) {
        curLine = nl;
      }
      continue;
    }

    if (source[i] == '\r') {
      if (i + 1 < source.size() && source[i + 1] == '\n') {
        i++;
      }
      curLine++;
      curCol = 1;
      i++;
      continue;
    }
    if (source[i] == '\n') {
      curLine++;
      curCol = 1;
      i++;
      continue;
